import React, { useState, useEffect } from 'react';
import VideoCompressor from './VideoCompressor';
import { db } from './firebase'; 
import { collection, addDoc, query, onSnapshot, serverTimestamp, doc, deleteDoc, orderBy } from 'firebase/firestore';

function App() {
  const [uploading, setUploading] = useState(false);
    const [progress, setProgress] = useState(0);
      const [showSettings, setShowSettings] = useState(false);
        const [gallery, setGallery] = useState([]);
          const [selectedItem, setSelectedItem] = useState(null); // Para el pantalla completa
            const [token, setToken] = useState(localStorage.getItem('tg_token') || '');
              const [chatId, setChatId] = useState(localStorage.getItem('tg_chatid') || '');

                useEffect(() => {
                    if (!db) return;
                        const q = query(collection(db, "media"), orderBy("timestamp", "desc"));
                            const unsubscribe = onSnapshot(q, (snapshot) => {
                                  const items = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
                                        setGallery(items);
                                            });
                                                return () => unsubscribe();
                                                  }, []);

                                                    const handleUpload = async (fileUrl, fileName, fileSize) => {
                                                        if (!token || !chatId) return alert('Configura el Bot en ⚙️');
                                                            setUploading(true);
                                                                setProgress(10); // Inicio simulado

                                                                    try {
                                                                          const response = await fetch(fileUrl);
                                                                                const blob = await response.blob();
                                                                                      const formData = new FormData();
                                                                                            formData.append('chat_id', chatId);
                                                                                                  
                                                                                                        const isVideo = blob.type.includes('video');
                                                                                                              const endpoint = isVideo ? 'sendVideo' : 'sendPhoto';
                                                                                                                    formData.append(isVideo ? 'video' : 'photo', blob, fileName);

                                                                                                                          // Usamos XMLHttpRequest para poder ver el progreso real de subida
                                                                                                                                const xhr = new XMLHttpRequest();
                                                                                                                                      xhr.open('POST', `https://api.telegram.org/bot${token}/${endpoint}`, true);

                                                                                                                                            xhr.upload.onprogress = (e) => {
                                                                                                                                                    if (e.lengthComputable) {
                                                                                                                                                              const percentComplete = Math.round((e.loaded / e.total) * 100);
                                                                                                                                                                        setProgress(percentComplete);
                                                                                                                                                                                }
                                                                                                                                                                                      };

                                                                                                                                                                                            xhr.onload = async () => {
                                                                                                                                                                                                    if (xhr.status === 200) {
                                                                                                                                                                                                              const tgData = JSON.parse(xhr.responseText);
                                                                                                                                                                                                                        await addDoc(collection(db, "media"), {
                                                                                                                                                                                                                                    fileName,
                                                                                                                                                                                                                                                type: blob.type,
                                                                                                                                                                                                                                                            messageId: tgData.result.message_id, 
                                                                                                                                                                                                                                                                        timestamp: serverTimestamp(),
                                                                                                                                                                                                                                                                                    preview: fileUrl 
                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                        setUploading(false);
                                                                                                                                                                                                                                                                                                                  setProgress(0);
                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                      xhr.send(formData);

                                                                                                                                                                                                                                                                                                                                          } catch (e) {
                                                                                                                                                                                                                                                                                                                                                alert('Error: ' + e.message);
                                                                                                                                                                                                                                                                                                                                                      setUploading(false);
                                                                                                                                                                                                                                                                                                                                                            setProgress(0);
                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                  };

                                                                                                                                                                                                                                                                                                                                                                    const deleteItem = (e, id, messageId) => {
                                                                                                                                                                                                                                                                                                                                                                        e.stopPropagation(); // Para que no se abra la foto al darle a la X
                                                                                                                                                                                                                                                                                                                                                                            if(window.confirm("¿Eliminar archivo?")) {
                                                                                                                                                                                                                                                                                                                                                                                  fetch(`https://api.telegram.org/bot${token}/deleteMessage?chat_id=${chatId}&message_id=${messageId}`);
                                                                                                                                                                                                                                                                                                                                                                                        deleteDoc(doc(db, "media", id));
                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                                                                                                                                                                return (
                                                                                                                                                                                                                                                                                                                                                                                                    <div className="min-h-screen bg-black text-white p-4">
                                                                                                                                                                                                                                                                                                                                                                                                          <style>{`
                                                                                                                                                                                                                                                                                                                                                                                                                  .grid-gallery { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; }
                                                                                                                                                                                                                                                                                                                                                                                                                          .thumb-container { position: relative; width: 100%; padding-top: 100%; background: #111; border-radius: 12px; overflow: hidden; border: 1px solid #222; cursor: pointer; }
                                                                                                                                                                                                                                                                                                                                                                                                                                  .thumb-content { position: absolute; top: 0; left: 0; width: 100%; height: 100%; object-fit: cover; }
                                                                                                                                                                                                                                                                                                                                                                                                                                          .play-icon { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); background: rgba(0,0,0,0.6); width: 35px; height: 35px; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 1px solid white; }
                                                                                                                                                                                                                                                                                                                                                                                                                                                  .modal { position: fixed; inset: 0; background: rgba(0,0,0,0.95); z-index: 50; display: flex; align-items: center; justify-content: center; padding: 10px; }
                                                                                                                                                                                                                                                                                                                                                                                                                                                          .progress-bar { width: 100%; bg-gray-800; border-radius: 10px; height: 8px; margin-top: 10px; overflow: hidden; }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .progress-fill { height: 100%; background: #3b82f6; transition: width 0.3s; }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        `}</style>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <header className="flex justify-between items-center mb-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <h1 className="text-xl font-bold text-blue-500 italic">CloudGallery</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button onClick={() => setShowSettings(!showSettings)} className="text-xl">⚙️</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </header>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {showSettings ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="bg-gray-900 p-6 rounded-2xl">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <input type="password" value={token} onChange={e => setToken(e.target.value)} className="w-full bg-black p-3 rounded mb-4 border border-gray-800" placeholder="Token" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <input value={chatId} onChange={e => setChatId(e.target.value)} className="w-full bg-black p-3 rounded mb-4 border border-gray-800" placeholder="Chat ID" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button onClick={() => setShowSettings(false)} className="w-full bg-blue-600 p-3 rounded font-bold">CERRAR</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="bg-gray-900 p-4 rounded-3xl mb-8 border border-gray-800">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <VideoCompressor onVideoReady={handleUpload} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {uploading && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="mt-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="flex justify-between text-[10px] mb-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <span>SUBIENDO...</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span>{progress}%</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="progress-bar">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="progress-fill" style={{ width: `${progress}%` }}></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="grid-gallery">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {gallery.map(item => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div key={item.id} className="thumb-container" onClick={() => setSelectedItem(item)}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {item.preview ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      item.type?.includes('video') ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <video src={item.preview} className="thumb-content opacity-60" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="play-icon text-white text-xs">▶</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <img src={item.preview} className="thumb-content" alt="" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="thumb-content flex items-center justify-center text-[10px]">CARGANDO...</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClick={(e) => deleteItem(e, item.id, item.messageId)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="absolute top-1 right-1 bg-red-600/80 w-5 h-5 rounded-full text-[10px] z-10"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >✕</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {/* MODAL DE PANTALLA COMPLETA */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {selectedItem && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="modal" onClick={() => setSelectedItem(null)}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button className="absolute top-5 right-5 text-white text-3xl z-50">✕</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="max-w-4xl w-full h-full flex items-center justify-center" onClick={e => e.stopPropagation()}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {selectedItem.type?.includes('video') ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <video 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            src={selectedItem.preview} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            controls 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            autoPlay 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="max-h-full max-w-full rounded-lg shadow-2xl"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <img 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    src={selectedItem.preview} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="max-h-full max-w-full object-contain rounded-lg shadow-2xl" 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    alt="" 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            export default App;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            